import sys

def main():
    N, D = map(int, sys.stdin.readline().split())
    schedules = [sys.stdin.readline().strip() for _ in range(N)]

    max_streak = 0
    current_streak = 0

    for day in range(D):
        all_free = True
        for person in range(N):
            if schedules[person][day] == 'x':
                all_free = False
                break
        if all_free:
            current_streak += 1
            if current_streak > max_streak:
                max_streak = current_streak
        else:
            current_streak = 0

    print(max_streak)

if __name__ == "__main__":
    main()
